// Helper function to get plant info by name
export const getPlantInfo = (plantName) => {
  // Try exact match first
  if (plantDatabase[plantName]) {
    return plantDatabase[plantName];
  }
  
  // Try case-insensitive match
  const normalizedName = plantName.toLowerCase();
  const match = Object.values(plantDatabase).find(
    plant => plant.name.toLowerCase() === normalizedName ||
             plant.localNames.some(local => local.toLowerCase() === normalizedName)
  );
  
  return match || null;
};

// Helper to get all plant names
export const getAllPlantNames = () => {
  return Object.keys(plantDatabase);
};
